@charset "UTF-8";
.bill-grid {
  display: grid;
  grid-auto-flow: column; /* keep in single row */
  grid-auto-columns: 180px;
  gap: 24px; /* increased from 12px → 24px */
  background: #f6f7f8;
  padding: 0px;
  font-family: system-ui, sans-serif;
  overflow-x: auto;
  border-radius: 10px;
  white-space: nowrap;
}

.label-column {
  background: #f6f7f8;
  padding: 5px 10px;
}

.label-cell {
  margin: 12px 0;
  color: #102349;
  font-size: 14px;
  font-weight: 500;
}

.bill-card {
  background: #fff;
  border-radius: 8px;
  box-shadow: 0 0 4px rgba(0, 0, 0, 0.08);
  padding: 12px 8px;
  text-align: center;
  min-width: 180px;
  flex-shrink: 0;
}

.bill-title {
  font-weight: 700;
  color: #102349;
  margin-bottom: 8px;
  font-size: 15px;
}

.value-cell {
  padding: 10px 6px;
  font-size: 14px;
  font-weight: 600;
  color: #102349;
  text-align: right;
}

.value-cell:nth-child(even) {
  background: #F1F2F4;
}

.value-cell:nth-child(odd) {
  background: #fff;
}

.value-cell a {
  color: #1b57d2;
  text-decoration: none;
}

.value-cell a:hover {
  text-decoration: underline;
}

