import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function App() {
  const bills = appsmith.model.data || [];
  if (!bills.length) return <div>No data available</div>;

  // Sort by invoice_date ascending
  const sortedBills = [...bills].sort(
    (a, b) => new Date(a.invoice_date) - new Date(b.invoice_date)
  );

  const lastYear = appsmith.model.lastYear || [];
  const priorBill = sortedBills[0];
  const currentBill = sortedBills[1];
  const nextBill = sortedBills[2];

  // Use triggerEvent for navigation requests to be handled by Appsmith page
  const handleNavigate = React.useCallback((bill_id) => {
    appsmith.triggerEvent("onNavigate", { bill_id: bill_id });
  }, []);

  const renderBillValue = (bill, key) => {
    if (!bill) return "-";
    const value = bill[key];

    if (key === "current_charges" || key === "past_due_amount" || key === "total_amount_due") {
      return `$${Number(value || 0).toFixed(2)}`;
    }

    if (key === "bill_id") {
      return (
        <a
          href="#"
          onClick={e => {
            e.preventDefault();
            handleNavigate(bill.bill_id);
          }}
          style={{ color: "#1b57d2", textDecoration: "none", cursor: "pointer" }}
        >
          {bill.bill_id}
        </a>
      );
    }

    return value || "-";
  };

  const fields = [
    { label: "Pear ID", key: "bill_id" },
    { label: "Invoice Date", key: "invoice_date" },
    { label: "Date Due", key: "due_date" },
    { label: "Current Charges", key: "current_charges" },
    { label: "Past Due", key: "past_due_amount" },
    { label: "Total Amount Due", key: "total_amount_due" },
  ];

  return (
    <div className="bill-grid">
      <div className="label-column">
        <h3 className="label-header"> </h3>
        {fields.map((f) => (
          <div key={f.key} className="label-cell">
            {f.label}
          </div>
        ))}
      </div>

      <div className="bill-card">
        <h3 className="bill-title">Approx. Last Year</h3>
        {fields.map((f) => (
          <div key={f.key} className="value-cell">
            {renderBillValue(lastYear, f.key)}
          </div>
        ))}
      </div>

      <div className="bill-card">
        <h3 className="bill-title">Prior Bill</h3>
        {fields.map((f) => (
          <div key={f.key} className="value-cell">
            {renderBillValue(priorBill, f.key)}
          </div>
        ))}
      </div>

      <div className="bill-card">
        <h3 className="bill-title">Current Bill</h3>
        {fields.map((f) => (
          <div key={f.key} className="value-cell">
            {renderBillValue(currentBill, f.key)}
          </div>
        ))}
      </div>

      <div className="bill-card">
        <h3 className="bill-title">Next Bill</h3>
        {fields.map((f) => (
          <div key={f.key} className="value-cell">
            {renderBillValue(nextBill, f.key)}
          </div>
        ))}
      </div>
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
